using System;
using System.IO;
using System.Runtime;
using HarfBuzzSharp;

// Create small test data (SOH is moved more easily)
byte[] testData = new byte[4096];
for (int i = 0; i < testData.Length; i++) testData[i] = (byte)((i ^ 0xAA) & 0xFF);

using MemoryStream stream = new MemoryStream(testData);
Blob blob = Blob.FromStream(stream);

// Save original data reference
var spanBefore = blob.AsSpan();
byte[] originalBytes = spanBefore.ToArray();

// Force aggressive GC compaction
GCSettings.LargeObjectHeapCompactionMode = GCLargeObjectHeapCompactionMode.CompactOnce;
GC.Collect(2, GCCollectionMode.Aggressive, true, true);
GC.WaitForPendingFinalizers();

// Allocate to fill holes
var allocs = new System.Collections.Generic.List<byte[]>();
for(int i=0; i<50; i++) allocs.Add(new byte[500_000]);

// Check for corruption
byte[] afterBytes = blob.AsSpan().ToArray();
if (!System.Linq.Enumerable.SequenceEqual(originalBytes, afterBytes))
{
    Console.WriteLine("❌ CORRUPTION DETECTED!");
    Environment.Exit(1);
}
Console.WriteLine("✓ Data OK");
